"""Pair matcher: flags candidate rows whose two amounts are within 5% of each other."""

TOOL = {
    "name": "amount_pair_matcher",
    "description": "Flags rows where amount and amount_b differ by no more than 5% of the larger.",
    "args_schema": {"type": "object", "properties": {"rows": {"type": "array"}},
                    "required": ["rows"]},
}
SELF_TEST = {
    "args": {"rows": [{"amount": 100.0, "amount_b": 103.0},
                      {"amount": 100.0, "amount_b": 200.0}]},
    "expect_keys": ["findings"],
}


def run(args: dict) -> dict:
    findings = []
    for row in args.get("rows", []):
        try:
            a = float(row.get("amount", 0))
            b = float(row.get("amount_b", 0))
        except (TypeError, ValueError):
            continue
        hi = max(abs(a), abs(b))
        if hi and abs(a - b) <= 0.05 * hi:
            findings.append(row)
    return {"findings": findings, "checked": len(args.get("rows", []))}
